28: func Query(ctx context.Context, dsInfo *models.DatasourceInfo, req backend.QueryDataRequest) (
29: 	*backend.QueryDataResponse, error) {
30: 	logger := glog.FromContext(ctx)
31: 	tRes := backend.NewQueryDataResponse()
32: 	r, err := runnerFromDataSource(dsInfo)
33: 	if err != nil {
34: 		return tRes, err
35: 	}
36: 	defer func(client *client) {
37: 		err := client.Close()
38: 		if err != nil {
39: 			logger.Warn("Failed to close fsql client", "err", err)
40: 		}
41: 	}(r.client)
42: 
43: 	if r.client.md.Len() != 0 {
44: 		ctx = metadata.NewOutgoingContext(ctx, r.client.md)
45: 	}
46: 
47: 	for _, q := range req.Queries {
48: 		qm, err := getQueryModel(q)
49: 		if err != nil {
50: 			tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(backend.StatusValidationFailed, backend.ErrorSourceDownstream, "bad request")
51: 			continue
52: 		}
53: 
54: 		logger.Info(fmt.Sprintf("InfluxDB executing SQL: %s", qm.RawSQL))
55: 		info, err := r.client.Execute(ctx, qm.RawSQL)
56: 		if err != nil {
57: 			errStr := fmt.Sprintf("flightsql: %s", err)
58: 			if grpcStatusErr, ok := status.FromError(err); ok {
59: 				switch grpcStatusErr.Code() {
60: 				case codes.InvalidArgument:
61: 					tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(backend.StatusBadRequest, backend.ErrorSourceDownstream, errStr)
62: 				case codes.PermissionDenied:
63: 					tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(backend.StatusForbidden, backend.ErrorSourceDownstream, errStr)
64: 				case codes.NotFound:
65: 					tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(backend.StatusNotFound, backend.ErrorSourceDownstream, errStr)
66: 				case codes.Unavailable:
67: 					tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(http.StatusServiceUnavailable, backend.ErrorSourceDownstream, errStr)
68: 				case codes.Unauthenticated:
69: 					tRes.Responses[q.RefID] = backend.ErrDataResponseWithSource(backend.StatusUnauthorized, backend.ErrorSourceDownstream, errStr)
70: 				default:
71: 					tRes.Responses[q.RefID] = backend.ErrDataResponse(backend.StatusInternal, errStr)
72: 				}
73: 			} else {
74: 				tRes.Responses[q.RefID] = backend.ErrDataResponse(backend.StatusInternal, errStr)
75: 			}
76: 			return tRes, nil
77: 		}
78: 		if len(info.Endpoint) != 1 {
79: 			tRes.Responses[q.RefID] = backend.ErrDataResponse(backend.StatusInternal, fmt.Sprintf("unsupported endpoint count in response: %d", len(info.Endpoint)))
80: 			return tRes, nil
81: 		}
82: 
83: 		reader, err := r.client.DoGetWithHeaderExtraction(ctx, info.Endpoint[0].Ticket)
84: 		if err != nil {
85: 			tRes.Responses[q.RefID] = backend.ErrDataResponse(backend.StatusInternal, fmt.Sprintf("flightsql: %s", err))
86: 			return tRes, nil
87: 		}
88: 		defer reader.Release()
89: 
90: 		headers, err := reader.Header()
91: 		if err != nil {
92: 			logger.Error(fmt.Sprintf("Failed to extract headers: %s", err))
93: 		}
94: 
95: 		tRes.Responses[q.RefID] = newQueryDataResponse(reader, *qm.Query, headers)
96: 	}
97: 
98: 	return tRes, nil
99: }
