129: // runnerFromDataSource creates a runner from the datasource model (the datasource instance's configuration).
130: func runnerFromDataSource(dsInfo *models.DatasourceInfo) (*runner, error) {
131: 	if dsInfo.URL == "" {
132: 		return nil, fmt.Errorf("missing URL from datasource configuration")
133: 	}
134: 
135: 	u, err := ParseURL(dsInfo.URL)
136: 	if err != nil {
137: 		return nil, err
138: 	}
139: 
140: 	md := metadata.MD{}
141: 	if dsInfo.DbName != "" {
142: 		md.Set("database", dsInfo.DbName)
143: 	}
144: 	if dsInfo.Token != "" {
145: 		md.Set("Authorization", fmt.Sprintf("Bearer %s", dsInfo.Token))
146: 	}
147: 
148: 	fsqlClient, err := newFlightSQLClient(u, md, !dsInfo.InsecureGrpc, dsInfo.TLSConfig, dsInfo.ProxyClient)
149: 	if err != nil {
150: 		return nil, err
151: 	}
152: 
153: 	return &runner{
154: 		client: fsqlClient,
155: 	}, nil
156: }
