167: func GetError(res *resourcepb.ErrorResult) error {
168: 	if res == nil {
169: 		return nil
170: 	}
171: 
172: 	status := &apierrors.StatusError{ErrStatus: metav1.Status{
173: 		Status:  metav1.StatusFailure,
174: 		Code:    res.Code,
175: 		Reason:  metav1.StatusReason(res.Reason),
176: 		Message: res.Message,
177: 	}}
178: 	if res.Details != nil {
179: 		status.ErrStatus.Details = &metav1.StatusDetails{
180: 			Group:             res.Details.Group,
181: 			Kind:              res.Details.Kind,
182: 			Name:              res.Details.Name,
183: 			UID:               types.UID(res.Details.Uid),
184: 			RetryAfterSeconds: res.Details.RetryAfterSeconds,
185: 		}
186: 		for _, c := range res.Details.Causes {
187: 			status.ErrStatus.Details.Causes = append(status.ErrStatus.Details.Causes, metav1.StatusCause{
188: 				Type:    metav1.CauseType(c.Reason),
189: 				Message: c.Message,
190: 				Field:   c.Field,
191: 			})
192: 		}
193: 	}
194: 	return status
195: }
